import React, { useState } from 'react';
import { toast } from 'react-toastify';
import { FaReply, FaTimes } from 'react-icons/fa';

const CommentForm = ({ onAddComment, replyingTo, onCancelReply }) => {
  const [comment, setComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!comment.trim()) {
      toast.error('Comment cannot be empty');
      return;
    }
    
    try {
      setIsSubmitting(true);
      await onAddComment(comment);
      setComment('');
    } catch (error) {
      console.error('Error submitting comment:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white dark:bg-gray-700 rounded-lg p-4 shadow-sm">
      {replyingTo && (
        <div className="flex items-center justify-between mb-2 bg-blue-50 p-2 rounded">
          <div className="flex items-center text-sm text-blue-700">
            <FaReply className="mr-1" />
            <span>Replying to <strong>{replyingTo}</strong></span>
          </div>
          <button 
            type="button" 
            onClick={onCancelReply}
            className="text-gray-500 hover:text-gray-700"
          >
            <FaTimes />
          </button>
        </div>
      )}
      
      <div className="mb-3">
        <textarea
          value={content}
          onChange={(e) => setContent(e.target.value)}
          placeholder="Write your comment..."
          className="w-full p-3 border border-gray-300 rounded-md focus:ring-2 focus:ring-green-500 focus:border-green-500"
          rows="3"
          required
        />
      </div>
      
      <div className="flex justify-end">
        <button
          type="submit"
          disabled={loading || !content.trim()}
          className={`px-4 py-2 rounded-md bg-green-600 text-white ${
            loading ? 'opacity-70 cursor-not-allowed' : 'hover:bg-green-700'
          }`}
        >
          {loading ? 'Posting...' : 'Post Comment'}
        </button>
      </div>
    </form>
  );
}

export default CommentForm;
